BEGIN;
--
-- Create model Application
--
CREATE TABLE "oauth2_provider_application" ("id" bigint NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "client_id" varchar(100) NOT NULL UNIQUE, "redirect_uris" text NOT NULL, "client_type" varchar(32) NOT NULL, "authorization_grant_type" varchar(32) NOT NULL, "client_secret" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "user_id" integer NULL, "skip_authorization" boolean NOT NULL, "created" timestamp with time zone NOT NULL, "updated" timestamp with time zone NOT NULL);
--
-- Create model AccessToken
--
CREATE TABLE "oauth2_provider_accesstoken" ("id" bigint NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "token" varchar(255) NOT NULL UNIQUE, "expires" timestamp with time zone NOT NULL, "scope" text NOT NULL, "application_id" bigint NULL, "user_id" integer NULL, "created" timestamp with time zone NOT NULL, "updated" timestamp with time zone NOT NULL);
--
-- Create model Grant
--
CREATE TABLE "oauth2_provider_grant" ("id" bigint NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "code" varchar(255) NOT NULL UNIQUE, "expires" timestamp with time zone NOT NULL, "redirect_uri" varchar(255) NOT NULL, "scope" text NOT NULL, "application_id" bigint NOT NULL, "user_id" integer NOT NULL, "created" timestamp with time zone NOT NULL, "updated" timestamp with time zone NOT NULL);
--
-- Create model RefreshToken
--
CREATE TABLE "oauth2_provider_refreshtoken" ("id" bigint NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "token" varchar(255) NOT NULL, "access_token_id" bigint NULL UNIQUE, "application_id" bigint NOT NULL, "user_id" integer NOT NULL, "created" timestamp with time zone NOT NULL, "updated" timestamp with time zone NOT NULL, "revoked" timestamp with time zone NULL);
--
-- Add field source_refresh_token to AccessToken
