ALTER TABLE "oauth2_provider_accesstoken" ADD COLUMN "source_refresh_token_id" bigint NULL UNIQUE CONSTRAINT "oauth2_provider_acce_source_refresh_token_e66fbc72_fk_oauth2_pr" REFERENCES "oauth2_provider_refreshtoken"("id") DEFERRABLE INITIALLY DEFERRED; SET CONSTRAINTS "oauth2_provider_acce_source_refresh_token_e66fbc72_fk_oauth2_pr" IMMEDIATE;
ALTER TABLE "oauth2_provider_application" ADD CONSTRAINT "oauth2_provider_application_user_id_79829054_fk_auth_user_id" FOREIGN KEY ("user_id") REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED;
